import React, { useState, useEffect, useRef } from 'react';
import { 
  User, 
  Crown,
  Cpu,
  Component,
  Palette,
  Database,
  LineChart,
  Mail,
  Linkedin,
  ChevronRight,
  TrendingUp
} from 'lucide-react';

// Estilos de fuentes
const fontStyles = `
  @import url('https://fonts.googleapis.com/css2?family=Playfair+Display:ital,wght@0,400;0,500;0,600;0,700;1,400&family=Montserrat:ital,wght@0,100;0,200;0,300;0,400;0,500;0,600;0,700;1,100;1,200;1,300;1,400&family=Inter:wght@100;200;300;400;500;600;700&display=swap');
  
  .font-playfair {
    font-family: 'Playfair Display', serif;
  }
  
  .font-montserrat {
    font-family: 'Montserrat', sans-serif;
  }
  
  .font-inter {
    font-family: 'Inter', sans-serif;
  }

  .header-icon-button {
    all: unset;
    box-sizing: border-box;
    margin: 0;
    padding: 0;
    border: none;
    background: none;
    font: inherit;
    color: inherit;
    cursor: pointer;
    outline: none;
  }

  .header-icon-button:focus {
    outline: none;
    ring: none;
  }

  .header-icon-button:hover {
    background: none !important;
    border: none !important;
  }

  /* Efectos de sombra corregidos */
  .text-shadow-dark {
    text-shadow: 0 10px 40px rgba(0, 0, 0, 0.9);
  }
  
  .text-shadow-medium {
    text-shadow: 0 6px 25px rgba(0, 0, 0, 0.8);
  }
  
  .text-shadow-light {
    text-shadow: 0 4px 20px rgba(0, 0, 0, 0.7);
  }

  .icon-glow {
    filter: drop-shadow(0 6px 20px rgba(255, 255, 255, 0.4)) 
            drop-shadow(0 0 15px rgba(255, 255, 255, 0.3));
  }

  .icon-glow-hover {
    filter: drop-shadow(0 0 40px rgba(255, 255, 255, 0.8)) 
            drop-shadow(0 10px 40px rgba(0, 0, 0, 0.9));
  }

  .box-shadow-glow {
    box-shadow: 0 10px 40px rgba(0, 0, 0, 0.8);
  }
`;

// Componente Reveal
const Reveal = ({ children, delay = 0 }) => {
  const [isVisible, setIsVisible] = useState(false);
  
  useEffect(() => {
    const timer = setTimeout(() => {
      setIsVisible(true);
    }, delay);
    
    return () => clearTimeout(timer);
  }, [delay]);
  
  return (
    <div className={`transition-all duration-700 ease-out ${
      isVisible 
        ? 'opacity-100 translate-y-0' 
        : 'opacity-0 translate-y-8'
    }`}>
      {children}
    </div>
  );
};

// Componente Listón Doblado
const RibbonCorner = ({ text, color = "#072D42", accentColor = "#0A3A5A" }) => {
  return (
    <div className="absolute -top-2 -right-2 z-30">
      {/* Listón principal con efecto doblado */}
      <div className="relative">
        {/* Parte frontal del listón */}
        <div 
          className="relative h-20 w-20 flex items-start justify-end pt-2 pr-2"
          style={{ 
            backgroundColor: color,
            clipPath: 'polygon(0 0, 100% 0, 100% 100%, 20% 100%, 0 80%)'
          }}
        >
          {/* Texto del listón */}
          <span 
            className="text-white font-montserrat text-xs font-bold tracking-widest transform rotate-45 origin-center"
            style={{ textShadow: '0 1px 2px rgba(0,0,0,0.3)' }}
          >
            {text}
          </span>
          
          {/* Efecto de doblez en la esquina */}
          <div 
            className="absolute bottom-0 left-0 w-5 h-5"
            style={{
              backgroundColor: accentColor,
              clipPath: 'polygon(0 0, 100% 100%, 0 100%)'
            }}
          ></div>
        </div>
        
        {/* Sombra del listón para efecto 3D */}
        <div 
          className="absolute -bottom-1 -right-1 h-20 w-20 opacity-20"
          style={{
            backgroundColor: '#000',
            clipPath: 'polygon(0 0, 100% 0, 100% 100%, 20% 100%, 0 80%)',
            zIndex: -1
          }}
        ></div>
      </div>
    </div>
  );
};

const EquipoPage = () => {
  const [activeSection, setActiveSection] = useState('delegacion');
  const [isHeaderShrunk, setIsHeaderShrunk] = useState(false);
  const [asideBottom, setAsideBottom] = useState('auto');
  const sectionRefs = useRef({});
  const asideRef = useRef(null);
  const uneteRef = useRef(null);
  const [scrollY, setScrollY] = useState(0);
  const tickingRef = useRef(false);

  // Insertar estilos en el head del documento
  useEffect(() => {
    const styleElement = document.createElement('style');
    styleElement.textContent = fontStyles;
    document.head.appendChild(styleElement);
    
    return () => {
      document.head.removeChild(styleElement);
    };
  }, []);

  // Scroll handler para parallax, sticky navigation y cálculo del aside
  useEffect(() => {
    const calculateAsideBottom = () => {
      const aside = asideRef.current;
      const uneteSection = uneteRef.current;
      
      if (!aside || !uneteSection) return;
      
      const asideRect = aside.getBoundingClientRect();
      const uneteRect = uneteSection.getBoundingClientRect();
      const viewportHeight = window.innerHeight;
      
      // Cuando la sección "Únete" está cerca del aside (2rem de margen)
      if (uneteRect.top < viewportHeight - 2 * 16) {
        const distanceFromBottom = viewportHeight - uneteRect.top + 2 * 16;
        setAsideBottom(`${distanceFromBottom / 16}rem`);
      } else {
        setAsideBottom('2rem'); // Margen normal de 2rem
      }
    };

    const handleScroll = () => {
      setIsHeaderShrunk(window.scrollY > 100);
      
      if (!tickingRef.current) {
        requestAnimationFrame(() => {
          setScrollY(window.scrollY);
          calculateAsideBottom();
          tickingRef.current = false;
        });
        tickingRef.current = true;
      }

      const sections = ['delegacion', 'backend', 'frontend', 'diseno', 'basedatos', 'dashboard', 'unete'];
      const scrollPosition = window.scrollY + 12.5 * 16; // 200px en rem (12.5rem)

      for (const sectionId of sections) {
        const element = sectionRefs.current[sectionId];
        if (element) {
          const { offsetTop, offsetHeight } = element;
          if (scrollPosition >= offsetTop && scrollPosition < offsetTop + offsetHeight) {
            setActiveSection(sectionId);
            break;
          }
        }
      }
    };
    
    window.addEventListener('scroll', handleScroll, { passive: true });
    window.addEventListener('resize', calculateAsideBottom);
    
    // Calcular inicialmente
    calculateAsideBottom();
    
    return () => {
      window.removeEventListener('scroll', handleScroll);
      window.removeEventListener('resize', calculateAsideBottom);
    };
  }, []);

  const scrollTo = (e, id) => {
    e.preventDefault();
    const el = sectionRefs.current[id];
    if (!el) return;
    
    const elementPosition = el.getBoundingClientRect().top + window.scrollY;
    const offsetPosition = elementPosition - 6.25 * 16; // 100px en rem (6.25rem)
    
    window.scrollTo({ top: offsetPosition, behavior: "smooth" });
    setActiveSection(id);
  };

  const parallaxStyle = {
    transform: `translate3d(0, ${scrollY * 0.4}px, 0)`
  };

  // Secciones con iconos y colores de fondo alternados
  const sections = [
    { 
      id: 'delegacion', 
      label: 'LIDERAZGO', 
      icon: Crown,
      bgColor: 'bg-white',
      ribbonColor: '#8B4513', // Café elegante para liderazgo
      ribbonAccent: '#A0522D'
    },
    { 
      id: 'backend', 
      label: 'BACKEND', 
      icon: Cpu,
      bgColor: 'bg-gray-50',
      ribbonColor: '#2E8B57', // Verde para backend
      ribbonAccent: '#3CB371'
    },
    { 
      id: 'frontend', 
      label: 'FRONTEND', 
      icon: Component,
      bgColor: 'bg-white',
      ribbonColor: '#1E90FF', // Azul para frontend
      ribbonAccent: '#6495ED'
    },
    { 
      id: 'diseno', 
      label: 'DISEÑO', 
      icon: Palette,
      bgColor: 'bg-gray-50',
      ribbonColor: '#9370DB', // Púrpura para diseño
      ribbonAccent: '#BA55D3'
    },
    { 
      id: 'basedatos', 
      label: 'BASE DE DATOS', 
      icon: Database,
      bgColor: 'bg-white',
      ribbonColor: '#FF8C00', // Naranja para base de datos
      ribbonAccent: '#FFA500'
    },
    { 
      id: 'dashboard', 
      label: 'ANALITYCS', 
      icon: LineChart,
      bgColor: 'bg-gray-50',
      ribbonColor: '#DC143C', // Rojo para analytics
      ribbonAccent: '#FF6347'
    }
  ];

  // Logos de los cuerpos
  const bodyLogos = [
    { id: 'delegacion', name: 'Liderazgo', icon: Crown, section: 'delegacion' },
    { id: 'backend', name: 'Backend', icon: Cpu, section: 'backend' },
    { id: 'frontend', name: 'Frontend', icon: Component, section: 'frontend' },
    { id: 'diseno', name: 'Diseño', icon: Palette, section: 'diseno' },
    { id: 'basedatos', name: 'Base de Datos', icon: Database, section: 'basedatos' },
    { id: 'dashboard', name: 'Analytics', icon: LineChart, section: 'dashboard' }
  ];

  // Datos de ejemplo del equipo con email y LinkedIn
  const teamMembers = {
    delegacion: [
      { 
        id: 1, 
        name: 'Ana Rodríguez', 
        position: 'Project Manager', 
        skills: ['Liderazgo', 'Estrategia', 'Gestión'],
        email: 'ana.rodriguez@orbis.com',
        linkedin: 'https://linkedin.com/in/ana-rodriguez'
      },
      { 
        id: 2, 
        name: 'Carlos Méndez', 
        position: 'Líder de Equipo', 
        skills: ['Coordinación', 'Planificación', 'Mentoría'],
        email: 'carlos.mendez@orbis.com',
        linkedin: 'https://linkedin.com/in/carlos-mendez'
      }
    ],
    backend: [
      { 
        id: 1, 
        name: 'Javier López', 
        position: 'Senior Backend Dev', 
        skills: ['Node.js', 'Python', 'APIs'],
        email: 'javier.lopez@orbis.com',
        linkedin: 'https://linkedin.com/in/javier-lopez'
      }
    ],
    frontend: [
      { 
        id: 1, 
        name: 'Sofía García', 
        position: 'Frontend Lead', 
        skills: ['React', 'TypeScript', 'UX'],
        email: 'sofia.garcia@orbis.com',
        linkedin: 'https://linkedin.com/in/sofia-garcia'
      }
    ],
    diseno: [
      { 
        id: 1, 
        name: 'Claudia Rojas', 
        position: 'Diseñadora Gráfica', 
        skills: ['Illustrator', 'Branding', 'Tipografía'],
        email: 'claudia.rojas@orbis.com',
        linkedin: 'https://linkedin.com/in/claudia-rojas'
      }
    ],
    basedatos: [
      { 
        id: 1, 
        name: 'Roberto Silva', 
        position: 'Database Architect', 
        skills: ['SQL', 'MongoDB', 'Optimización'],
        email: 'roberto.silva@orbis.com',
        linkedin: 'https://linkedin.com/in/roberto-silva'
      }
    ],
    dashboard: [
      { 
        id: 1, 
        name: 'Patricia Navarro', 
        position: 'Dashboard Designer', 
        skills: ['DataViz', 'Tableau', 'Storytelling'],
        email: 'patricia.navarro@orbis.com',
        linkedin: 'https://linkedin.com/in/patricia-navarro'
      }
    ]
  };

  return (
    <div className="min-h-screen bg-beige font-inter">
      
      {/* HEADER */}
      <div className="h-[80vh] min-h-[25rem] max-h-[50rem] mb-9 overflow-hidden relative">
        <header className="relative h-full">
          <div className="absolute inset-0 w-full h-full overflow-hidden" style={parallaxStyle}>
            <img 
              src="/media/historiapage/futbol.jpg"
              alt="Nuestro Equipo - Orbis Empresarial"
              className="w-full h-full object-cover object-top"
            />
            <div className="absolute inset-0 bg-gradient-radial from-[rgba(7,45,66,0.4)] via-[rgba(7,45,66,0.2)] to-transparent"></div>
          </div>
          
          <div className="relative z-30 p-8 lg:p-20 text-white h-full flex flex-col justify-center items-center text-center">
            <div className="absolute inset-0 bg-gradient-radial from-[rgba(7,45,66,0.8)] via-[rgba(7,45,66,0.4)] to-transparent pointer-events-none"></div>

            <div className="relative z-10 w-full max-w-6xl">
              <div className="text-shadow-dark mb-8">
                <h1 className="font-playfair text-6xl lg:text-8xl font-normal leading-[0.9] tracking-tight mb-4 text-white">
                  Nuestro Equipo
                </h1>
              </div>
              
              <div className="mb-8 text-shadow-medium">
                <h2 className="font-montserrat text-2xl lg:text-3xl font-light tracking-[0.2em] uppercase text-white/95 mb-3">
                  Talento y Excelencia
                </h2>
                <div className="h-px w-32 bg-white/80 mb-4 mx-auto shadow-glow-white"></div>
              </div>
              
              <div className="mb-12 text-shadow-light">
                <p className="font-inter text-xl lg:text-2xl font-extralight tracking-wide max-w-2xl mx-auto text-white/95 leading-relaxed">
                  Conoce al equipo profesional detrás de Orbis Empresarial. 
                  Expertos comprometidos con la excelencia y la innovación.
                </p>
              </div>

              <div className="flex flex-wrap gap-8 lg:gap-12 mt-12 justify-center">
                {bodyLogos.map((body) => {
                  const IconComponent = body.icon;
                  return (
                    <div key={body.id} className="flex flex-col items-center">
                      <button
                        onClick={(e) => scrollTo(e, body.section)}
                        className="header-icon-button group relative transform transition-all duration-700 ease-out hover:scale-110 hover:-translate-y-2 
                          bg-transparent border-none outline-none focus:ring-0 focus:outline-none"
                        aria-label={`Ir a la sección ${body.name}`}
                      >
                        <div className="relative">
                          <div className="absolute inset-0 opacity-0 group-hover:opacity-100 transition-all duration-500"></div>
                          <IconComponent className="relative w-16 h-16 lg:w-20 lg:h-20 text-white 
                            icon-glow group-hover:icon-glow-hover
                            transition-all duration-500 ease-out
                            group-hover:scale-110" />
                          <div className="absolute inset-0 bg-white/0 group-hover:bg-white/30 rounded-full blur-md group-hover:blur-xl transition-all duration-700 ease-out scale-0 group-hover:scale-125"></div>
                          <div className="absolute -inset-4 border-2 border-white/0 group-hover:border-white/40 rounded-full transition-all duration-500 ease-out scale-0 group-hover:scale-100"></div>
                        </div>
                        
                        <div className="absolute -top-16 left-1/2 transform -translate-x-1/2 opacity-0 group-hover:opacity-100 transition-all duration-500 ease-out pointer-events-none">
                          <div className="bg-black/90 text-white text-sm font-montserrat px-4 py-2 rounded-lg whitespace-nowrap backdrop-blur-md 
                            box-shadow-glow border border-white/20
                            text-shadow-dark">
                            Ir a {body.name}
                            <div className="absolute -bottom-1 left-1/2 transform -translate-x-1/2 w-2 h-2 bg-black/90 rotate-45 border-b border-r border-white/20"></div>
                          </div>
                        </div>
                      </button>
                      
                      <div className="mt-4">
                        <span className="font-montserrat text-white/90 text-sm lg:text-base font-light tracking-wide 
                          text-shadow-light transition-all duration-300 
                          group-hover:text-white group-hover:text-shadow-glow">
                          {body.name}
                        </span>
                      </div>
                    </div>
                  );
                })}
              </div>
            </div>
          </div>
        </header>
      </div>

      <main className="py-0">
        {/* NAVEGACIÓN MÓVIL */}
        <div className="block lg:hidden mb-8 px-4 sm:px-6 lg:px-8">
          <nav className="flex flex-row gap-2 overflow-x-auto py-4" aria-label="Navegación por secciones">
            {sections.map((s) => (
              <button
                key={s.id}
                onClick={(e) => scrollTo(e, s.id)}
                className={`
                  relative text-left py-3 px-4 transition-colors duration-200 whitespace-nowrap
                  rounded-lg border border-gray-400/30 bg-white/10
                  hover:bg-gray-400/10
                  ${
                    activeSection === s.id 
                      ? 'bg-gray-400/20 font-medium'
                      : 'font-light opacity-80 hover:opacity-100'
                  }
                `}
              >
                <span className="tracking-widest text-sm text-blue-900 font-montserrat">{s.label}</span>
              </button>
            ))}
          </nav>
        </div>

        <div className="flex flex-col lg:flex-row gap-8 lg:items-start px-4 sm:px-6 lg:px-8">
          {/* ASIDE STICKY CON BOTTOM DINÁMICO */}
          <aside 
            ref={asideRef}
            className="hidden lg:block lg:w-2/6 sticky"
            style={{ 
              top: '10rem',
              bottom: asideBottom 
            }}
            aria-label="Navegación lateral"
          >
            <nav className="flex lg:flex-col gap-0 rounded-lg overflow-hidden border border-gray-400/30 bg-white/10">
              {sections.map((s) => (
                <button
                  key={s.id}
                  onClick={(e) => scrollTo(e, s.id)}
                  className={`
                    relative group flex items-center justify-between py-3 px-4 transition-all duration-300
                    after:content-[''] after:absolute after:left-0 after:bottom-0
                    after:w-full after:h-px after:bg-gray-400
                    after:origin-center after:transition-transform after:duration-300 after:ease-out
                    border-b border-gray-400/20 last:border-b-0
                    hover:bg-gray-400/10 w-full text-left
                    ${
                      activeSection === s.id 
                        ? 'font-medium opacity-100 after:scale-x-100 bg-gray-400/20'
                        : 'font-extralight opacity-70 hover:opacity-100 after:scale-x-0 hover:after:scale-x-100'
                    }
                  `}
                >
                  <div className="flex items-center gap-3">
                    <s.icon className="w-4 h-4 text-blue-900 opacity-70 group-hover:opacity-100 transition-opacity duration-300" />
                    <span className={`
                      tracking-widest text-sm text-blue-900 font-montserrat
                      ${activeSection === s.id ? 'font-semibold' : 'font-extralight'}
                    `}>
                      {s.label}
                    </span>
                  </div>
                  <div className="opacity-0 group-hover:opacity-100 transition-all duration-300 transform translate-x-2 group-hover:translate-x-0">
                    <ChevronRight className="w-3 h-3 text-blue-900" />
                  </div>
                </button>
              ))}
            </nav>
          </aside>

          {/* CONTENIDO PRINCIPAL CON LISTONES */}
          <section className="w-full lg:w-5/6 flex flex-col px-0">
            {sections.map((section, index) => (
              <div key={section.id} className={`${section.bgColor} relative`}>
                {/* LISTÓN DOBLADO EN ESQUINA SUPERIOR DERECHA */}
                <RibbonCorner 
                  text={section.label}
                  color={section.ribbonColor}
                  accentColor={section.ribbonAccent}
                />

                {/* LÍNEA SEPARADORA ELEGANTE - Solo entre secciones del mismo color */}
                {index > 0 && sections[index - 1].bgColor === section.bgColor && (
                  <div className="h-px w-full bg-gradient-to-r from-transparent via-blue-900/10 to-transparent"></div>
                )}

                {/* SEPARADOR DE FONDO - Cuando cambia el color de fondo */}
                {index > 0 && sections[index - 1].bgColor !== section.bgColor && (
                  <div className="h-2 w-full bg-gradient-to-b from-gray-50 to-white"></div>
                )}

                <div
                  id={section.id}
                  ref={(el) => (sectionRefs.current[section.id] = el)}
                  className="scroll-mt-24"
                >
                  <div className="py-12 md:py-16 px-4 sm:px-6 lg:px-8">
                    <Reveal delay={index * 100}>
                      <div className="mb-12 md:mb-16 text-center">
                        <div className="flex items-center justify-center gap-3 mb-4">
                          <section.icon className="w-8 h-8 text-blue-900" />
                          <h2 className="font-playfair text-3xl md:text-4xl lg:text-5xl text-blue-900 font-normal">
                            {section.label}
                          </h2>
                        </div>
                        <div className="h-px w-20 bg-blue-900/60 mx-auto"></div>
                      </div>
                    </Reveal>

                    {/* TARJETAS COMPACTAS MEJORADAS */}
                    <div className="flex justify-center">
                      <div className="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-3 gap-6 w-full max-w-7xl">
                        {teamMembers[section.id].map((member, memberIndex) => (
                          <Reveal key={member.id} delay={(index * 100) + (memberIndex * 100)}>
                            <div className="relative bg-white rounded-2xl shadow-lg border border-blue-900/10 hover:shadow-xl hover:border-blue-900/20 transition-all duration-500 ease-out group overflow-hidden">
                              
                              {/* EFECTO DE HOVER - FONDO AZUL QUE SE EXPANDE */}
                              <div className="absolute inset-0 bg-gradient-to-br from-blue-900 to-blue-800 opacity-0 group-hover:opacity-100 transition-all duration-500 ease-out rounded-2xl" />
                              
                              {/* ICONO DE SECCIÓN COMO FONDO GRANDE */}
                              <div className="absolute right-0 top-1/2 transform -translate-y-1/2 flex items-center justify-center opacity-5 group-hover:opacity-15 transition-all duration-700 ease-out z-10">
                                <section.icon className="w-48 h-48 text-blue-900 group-hover:text-white transition-colors duration-500 group-hover:scale-105" />
                              </div>
                              
                              {/* CONTENIDO PRINCIPAL */}
                              <div className="relative z-20 p-5">
                                {/* PRIMERA FILA: PERFIL + NOMBRE Y POSICIÓN */}
                                <div className="flex items-start gap-4 mb-4">
                                  {/* ICONO DE PERFIL - IZQUIERDA */}
                                  <div className="flex-shrink-0">
                                    <div className="w-14 h-14 rounded-full bg-gradient-to-br from-blue-900 to-blue-800 group-hover:from-white group-hover:to-gray-100 flex items-center justify-center group-hover:scale-110 transition-all duration-500 border-2 border-white group-hover:border-blue-900 shadow-md">
                                      <User className="w-6 h-6 text-white group-hover:text-blue-900 transition-colors duration-500" />
                                    </div>
                                  </div>
                                  
                                  {/* NOMBRE Y POSICIÓN */}
                                  <div className="flex-1 min-w-0">
                                    <h3 className="font-playfair text-lg text-blue-900 group-hover:text-white font-normal mb-1 transition-colors duration-300 truncate">
                                      {member.name}
                                    </h3>
                                    <p className="font-inter text-blue-900/80 group-hover:text-white/90 text-sm font-medium truncate transition-colors duration-300">
                                      {member.position}
                                    </p>
                                  </div>
                                </div>
                                
                                {/* SEGUNDA FILA: CONTACTO Y SKILLS */}
                                <div className="space-y-3">
                                  {/* CONTACTO */}
                                  <div className="flex items-center justify-between">
                                    <div className="flex items-center gap-3">
                                      {/* Email con texto */}
                                      <a 
                                        href={`mailto:${member.email}`}
                                        className="text-blue-900/70 group-hover:text-white/80 hover:text-blue-900 group-hover:hover:text-white transition-colors duration-300 flex items-center gap-1"
                                        title="Enviar email"
                                      >
                                        <Mail className="w-3 h-3 flex-shrink-0" />
                                        <span className="text-xs font-inter truncate max-w-[120px]">
                                          {member.email.split('@')[0]}
                                        </span>
                                      </a>
                                      
                                      {/* LinkedIn */}
                                      <a 
                                        href={member.linkedin}
                                        target="_blank"
                                        rel="noopener noreferrer"
                                        className="text-blue-900/70 group-hover:text-white/80 hover:text-blue-700 group-hover:hover:text-white transition-colors duration-300 flex-shrink-0"
                                        title="LinkedIn"
                                      >
                                        <Linkedin className="w-4 h-4" />
                                      </a>
                                    </div>
                                  </div>
                                  
                                  {/* SKILLS */}
                                  <div className="flex flex-wrap gap-1">
                                    {member.skills.map((skill, skillIndex) => (
                                      <span 
                                        key={skillIndex}
                                        className="inline-flex items-center px-2 py-1 bg-beige group-hover:bg-white/20 text-blue-900 group-hover:text-white text-xs rounded-md font-inter transition-all duration-300 hover:bg-beige-dark group-hover:hover:bg-white/30"
                                      >
                                        {skill}
                                      </span>
                                    ))}
                                  </div>
                                </div>
                              </div>
                            </div>
                          </Reveal>
                        ))}
                      </div>
                    </div>
                  </div>
                </div>
              </div>
            ))}

            {/* SEPARADOR ELEGANTE */}
            <div className="flex items-center justify-center my-16 bg-white py-8">
              <div className="h-px w-32 bg-blue-900/20"></div>
              <div className="mx-4">
                <TrendingUp className="w-6 h-6 text-blue-900/40" />
              </div>
              <div className="h-px w-32 bg-blue-900/20"></div>
            </div>
          </section>
        </div>

        {/* SECCIÓN "ÚNETE" - ANCHO COMPLETO CON FONDO ESPECIAL */}
        <div 
          id="unete"
          ref={(el) => {
            sectionRefs.current.unete = el;
            uneteRef.current = el;
          }}
          className="scroll-mt-24 relative min-h-[31.25rem] w-screen -ml-[calc(50vw-50%)] -mr-[calc(50vw-50%)] mt-16"
        >
          <div className="absolute inset-0 w-full h-full">
            <img 
              src="/media/historiapage/TEAMB.jpg"
              alt="Únete a nuestro equipo"
              className="w-full h-full object-cover"
            />
            <div className="absolute inset-0 bg-gradient-to-br from-blue-900/90 to-blue-800/90"></div>
          </div>
          
          <div className="relative z-10 py-20 md:py-24">
            <Reveal>
              <div className="text-center max-w-3xl mx-auto text-white px-4 sm:px-6">
                <h2 className="font-playfair text-3xl md:text-4xl lg:text-5xl text-white mb-6 font-normal">
                  Únete a Nuestro Equipo
                </h2>
                <div className="h-px w-20 bg-white/70 mx-auto mb-8"></div>
                <p className="font-inter text-white/90 mb-10 text-lg leading-relaxed max-w-2xl mx-auto">
                  Buscamos talento apasionado por la innovación 
                  y la preservación de la memoria empresarial.
                </p>
                <button className="bg-white/20 hover:bg-white/30 text-white px-8 py-4 md:px-10 md:py-4 rounded-lg font-montserrat font-medium tracking-wide transition-all duration-300 transform hover:scale-105 hover:shadow-xl text-lg border border-white/30 hover:border-white/50">
                  Ver Oportunidades
                </button>
              </div>
            </Reveal>
          </div>
        </div>
      </main>
    </div>
  );
};

export default EquipoPage;
